// Coordinator for Two-Phase Commit
coordinator_state = "INITIAL"
participants = []
votes = {}

// Phase 1: Prepare
function prepare(transaction):
 coordinator_state = "PREPARING"
 votes = {}

 for each participant in participants:
 send(PREPARE, transaction) to participant

 // Wait for all votes or timeout
 timeout = 30 seconds
 while hasPendingResponses() and not timeout:
 wait()

 if timeout occurred:
 coordinator_state = "ABORTED"
 broadcast(ABORT, transaction)
 return ABORTED

 // Check all votes
 all_yes = true
 for vote in votes:
 if vote == "NO":
 all_yes = false
 break

 if all_yes:
 coordinator_state = "COMMITTING"
 broadcast(COMMIT, transaction)
 coordinator_state = "COMMITTED"
 return COMMITTED
 else:
 coordinator_state = "ABORTED"
 broadcast(ABORT, transaction)
 return ABORTED

function handle_vote(participant, vote):
