// Check causality
function causal_precedes(eventA, eventB):
 // Returns true if A causally happened before B
 less_or_equal = true
 strictly_less = false

 for k in range(n):
 if eventA.vector[k] > eventB.vector[k]:
 return false // B cannot happen after A
 less_or_equal = less_or_equal and (eventA.vector[k] <= eventB.vector[k])
 strictly_less = strictly_less or (eventA.vector[k] < eventB.vector[k])

 return less_or_equal and strictly_less

function concurrent(eventA, eventB):
 return not causal_precedes(eventA, eventB) and not causal_precedes(eventB, eventA)
